---播放立绘

---@class LBattleSkillActDrawing
local LBattleSkillActDrawing = classX("LBattleSkillActDrawing", nil)

---@param player LBattleSkillPlayer
---@param effData LSkillEffectData
---@param playState LBattleSkillPlayState
function LBattleSkillActDrawing.Execute(player,effData, playState)
    local effRes = effData.effRes --光效名字
    local playTime = effData.playTime --光效持续时间
    local dissipateTime = effData.dissipateTime --光效消散时间
    local offset = effData.effOffsetStart --偏移
    local offsetType = effData.effStartType or 1
    local isUpperLayer = effData.battleHierarchy == 0

    local obj = player:GetTargetAtkUnitView()
    local _viewMgr = player:GetViewMgr()
    local _skillHurtDataList = player:GetSkillHurtDataList()

    local atkPos = obj:GetPosition()
    local atkSide = obj:GetTeamIdx()
    local id= nil
    local skillHurtData = _skillHurtDataList or {}
    for k,v in ipairs(skillHurtData) do
        for k1,v1 in ipairs(v) do
            if v1.hitHurt then
                id = v1.hitHurt.eId
                break
            end
        end
    end

    local targetPos=nil
    if id then
        local tarObj = _viewMgr:GetUnitView(id)
        targetPos = tarObj:GetPosition()
    end
    local pos = player:GetEffStartPos(offsetType,atkSide,atkPos,targetPos)
    local actOffset = offset
    if atkSide== BattleTeamSide.teamB then
        actOffset = Vector3.New(-offset.x,offset.y,0)
    end
    local effPos = actOffset + pos

    local effectCtrl = _viewMgr:GetEffectCtrl()
    local rootTrans = _viewMgr:GetEffectRootTrans()
    local effect = effectCtrl:MakeBattleSkillEffectObj(rootTrans, effRes, effPos, LFightConst.DIRECTION_LEFT, 0, playTime,dissipateTime,LFightEffect.SPINE)
    local para =
    {
        scale = 1,
        localPos = nil,
        isUpperLayer = isUpperLayer,
        onStartCall = function()
            player:HideAllBlood()
        end,
        onEndCall = function()
            player:RecoverBloodShow()
        end
    }
    effect:SetEffectPara(para)
    effectCtrl:AddEffect(effect)
end

return LBattleSkillActDrawing